#include <iostream>
using namespace std;

string reverseString(string s) {
    string r = \"\";
    for (int i = s.length() - 1; i >= 0; i--) {
        r += s[i];
    }
    return r;

}

int main() {
    string s; cin >> s;
    string reversed = reverseString(s);
    cout << reversed << endl;
    return 0;
}
